import React, { createContext, useContext, useState, useEffect, useCallback, useMemo } from "react";
import { jwtDecode } from "jwt-decode";

const UserContext = createContext();

export function UserProvider({ children }) {
  const [user, setUser] = useState(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [loading, setLoading] = useState(true);

  const checkToken = useCallback(() => {
    const token = localStorage.getItem("token");

    if (token) {
      try {
        const decoded = jwtDecode(token);
        console.log("Token decoded successfully:", decoded);
        setUser({
          userId: decoded.sub || decoded.userId || decoded.id,
          username: decoded.username || decoded.preferred_username,
          authToken: token
        });
        setIsLoggedIn(true);
      } catch (error) {
        console.error("Failed to decode token:", error);
        localStorage.removeItem("token");
        setUser(null);
        setIsLoggedIn(false);
      }
    } else {
      setUser(null);
      setIsLoggedIn(false);
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    // Check token on app load
    checkToken();

    // Listen for login and logout events
    window.addEventListener("login", checkToken);
    window.addEventListener("logout", () => {
      setUser(null);
      setIsLoggedIn(false);
    });

    return () => {
      window.removeEventListener("login", checkToken);
      window.removeEventListener("logout", () => {
        setUser(null);
        setIsLoggedIn(false);
      });
    };
  }, [checkToken]);

  const login = useCallback((token) => {
    console.log("Login called with token:", token);
    localStorage.setItem("token", token);
    checkToken();
  }, [checkToken]);

  const logout = useCallback(() => {
    console.log("Logout called");
    localStorage.removeItem("token");
    setUser(null);
    setIsLoggedIn(false);
    window.dispatchEvent(new Event("logout"));
  }, []);

  // Memoize the context value to prevent unnecessary re-renders
  const value = useMemo(
    () => ({
      user,
      isLoggedIn,
      loading,
      userId: user?.userId,
      username: user?.username,
      login,
      logout
    }),
    [user, isLoggedIn, loading, login, logout]
  );

  return (
    <UserContext.Provider value={value}>
      {children}
    </UserContext.Provider>
  );
}

export function useUser() {
  const context = useContext(UserContext);

  if (!context) {
    throw new Error("useUser must be used within a UserProvider");
  }

  return context;
}
